extends InputMap

# Mobile input handler for touch-based gameplay
# Supports swipe gestures and tap actions

@export var touch_threshold: float = 100.0
@export var swipe_duration: float = 0.5

var _touch_start_time: float = 0.0
var _swipe_direction: Vector2 = Vector2.ZERO
var _last_touch_position: Vector2 = Vector2.ZERO

func _ready():
    Input.on_input_event.connect(_on_input_event)

func _on_input_event(event):
    if event is InputEventTouch:
        _handle_touch_event(event)

func _handle_touch_event(event):
    match event:
        InputEventTouch(TouchStart):
            _touch_start_time = get_tree().elapsed_time
            _last_touch_position = event.position

            if event.pressed:
                emit_signal("attack")
        InputEventTouch(TouchMove):
            if event.pressed:
                var current_position = event.position
                var delta = current_position - _last_touch_position
                _last_touch_position = current_position

                if abs(delta.x) > touch_threshold or abs(delta.y) > touch_threshold:
                    _swipe_direction = delta
                    if abs(_swipe_direction.x) > abs(_swipe_direction.y):
                        _swipe_direction = Vector2(1, 0) if delta.x > 0 else Vector2(-1, 0)
                    else:
                        _swipe_direction = Vector2(0, 1) if delta.y > 0 else Vector2(0, -1)

                    if get_tree().elapsed_time - _touch_start_time > swipe_duration:
                        if _swipe_direction.x > 0:
                            emit_signal("move_right")
                        elif _swipe_direction.x < 0:
                            emit_signal("move_left")
                        elif _swipe_direction.y > 0:
                            emit_signal("move_down")
                        elif _swipe_direction.y < 0:
                            emit_signal("move_up")
        InputEventTouch(TouchEnd):
            if event.pressed:
                emit_signal("attack")

func _input(event):
    pass

signal attack()
signal move_right()
signal move_left()
signal move_up()
signal move_down()
